DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "parserNumberWithUnits.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context('Numeric'); $name = randomPerson(); $initial = random(55,62); $rate = random(20,30); $final = 212; $solution = ($final - $initial)/$rate; $time = NumberWithUnits("$solution min");
############################################################ # Body ############################################################
BEGIN_PGML [$name] puts a pot of water from the tap onto the stove and turns the burner all the way up. The water temperature starts at [`[$initial]\,^{\circ}F`] and climbs steadily up to the boiling point of [`[$final]\,^{\circ}F\text{,}`] raising at a rate of [`[$rate]\,\frac{^{\circ}F}{\text{min}}\text{.}`] How long will it take for the pot to boil?
[_]{$time}{20}
END_PGML
